Rule.Source:
  import sailpoint.object.Link;
  import sailpoint.object.Field;
  import sailpoint.object.Identity;
  import sailpoint.object.Application;        
  import sailpoint.object.ProvisioningPlan;
  import sailpoint.object.ProvisioningPlan.AccountRequest;
  import sailpoint.object.ProvisioningPlan.AttributeRequest;
  import sailpoint.object.ProvisioningResult;
  import sailpoint.object.ProvisioningPlan.AccountRequest.Operation; 
  import sailpoint.object.Custom;
  import sailpoint.object.Attributes;
  import sailpoint.tools.Util;
  import java.util.Map;
  import java.util.HashMap;
  import java.util.concurrent.TimeUnit;
  import sailpoint.object.PasswordPolicy;
  import sailpoint.api.TaskManager;
  import sailpoint.api.PasswordGenerator;
  import org.apache.log4j.Logger;
  import org.ascn.utils.GeneralUtils;

  String logName = "org.ascn.rule.Ascension-Gsuite-FieldValue-Rule"; 

  if (null == identity) {
    throw new RuntimeException("identity is null");   
  }

  String currentField = null;
  String email = identity.getEmail();
  String identityType = identity.getType();
  String hrType = getHRType(identity);
  String firstName = identity.getFirstname();
  String lastName = identity.getLastname();
  String company = identity.getAttribute("company");
  String gsuiteStatus = identity.getAttribute("gsuiteStatus");
  String gsuiteLN = identity.getAttribute("gsuiteLastName");
  String sam = identity.getAttribute("samAccountName");
  String vendorName = identity.getAttribute("vendorName");
  String empClass = identity.getAttribute("employeeClass");

  String defaultOU = null;
  String suffixValue = null;
  Custom gsuiteCustomObject = null;
  String GSUITE_CUSTOM_OBJECT_NAME="Ascension-Custom-Gsuite";
  gsuiteCustomObject = context.getObject(Custom.class,GSUITE_CUSTOM_OBJECT_NAME);

  debug(logName, "ENTERING RULE: " + "Ascension-Gsuite-FieldValue-Rule");

  Map gsuiteStatusMap = new HashMap();

  String fieldName = field.getName();
  if (null != fieldName) {
    currentField = fieldName.substring(fieldName.indexOf(':') + 1);
  } else {
    taskResult.addMessage("Field Name Is Null: "+fieldName+" Identity Name: "+identity.getName());
  }

  //Begin Common Field Logic

  if ("prefixField".equalsIgnoreCase(currentField)){ //prefixField
    debug(logName, "CURRENT FIELD: " + currentField);
    prefixValue = determineEmailPrefix(identity);
    return prefixValue;
  }

  if ("suffixField".equalsIgnoreCase(currentField)){ //suffixField
    debug(logName, "CURRENT FIELD: " + currentField);
    if ((empClass != null && gsuiteCustomObject != null && !gsuiteCustomObject.get("emplClassForExternalDomainOverride").contains(empClass) && Util.nullSafeCaseInsensitiveEq(identityType, "contractor")) || Util.nullSafeCaseInsensitiveEq(identityType, "non-hr contractor") || (Util.nullSafeCaseInsensitiveEq(identityType, "physician") && !Util.nullSafeCaseInsensitiveEq(hrType, "EMP"))) {

      if (Util.isNotNullOrEmpty(email)) { //Identity currently has email value

        field.setRequired(false);
        suffixValue = "ascension-external.org"; //Not used in provisioning when sourced from here; has to be supplied a value to fulfill dependency requirement of primaryEmail

      } else { //Identity does not have email value; need details to generate one

        if (project != null) {

          String operationName = "";

          try{

            ProvisioningPlan plan = project.getMasterPlan();

            if (plan != null){
              List accountRequests = plan.getAccountRequests();
              if (null != accountRequests && !accountRequests.isEmpty()){
                for(AccountRequest accountRequest : accountRequests){
                  String appName = accountRequest.getApplication();
                  Application application = context.getObjectByName(Application.class, appName);
                  if (application != null){
                    String appType = application.getType();
                    if (appType.equalsIgnoreCase("Active Directory - Direct") && (null != accountRequest.getOperation() && AccountRequest.Operation.Enable.equals(accountRequest.getOperation()))) {
                      Attributes atts  = new Attributes();
                      if (accountRequest.getArguments() != null){
                        atts = accountRequest.getArguments();
                        operationName = atts.get("operationName");
                        break;
                      }
                    }
                  }
                }
              }
            }
          } catch(Exception e){
            error(logName, "Error in calculating operation name: " + e.getMessage());
          }

          String requester = project.getRequester();

          if (Util.isNullOrEmpty(requester)) { //Request generated via automation; use default domain value

            suffixValue = "ascension-external.org";

          } else if (Util.isNotNullOrEmpty(operationName) && operationName.equalsIgnoreCase("Rehire")){

            suffixValue = "ascension-external.org";

          } else { //Request generated via Manage User Access; allow requester to select domain value

            suffixValue = null;

          }

        }

      }

    } else {

      suffixValue = determinePrimaryDomain(identity);

    }
    return suffixValue;
  }

  if ("password".equalsIgnoreCase(currentField)){ //password
    debug(logName, "CURRENT FIELD: " + currentField);
    PasswordPolicy policy = context.getObjectByName(PasswordPolicy.class, "Ascension-PasswordPolicy-Gsuite");
    PasswordGenerator passwordGenerator = new PasswordGenerator(context);
    String password = passwordGenerator.generatePassword(policy);
    debug(logName, "value: " + password);
    return password;
  }

  if ("isAdmin".equalsIgnoreCase(currentField)){ //isAdmin
    debug(logName, "CURRENT FIELD: " + currentField);
    debug(logName, "value: " + "false");
    return false;
  }

  if ("active".equalsIgnoreCase(currentField)){ //active
    debug(logName, "CURRENT FIELD: " + currentField);
    debug(logName, "value: " + "false");
    return false;
  }

  if ("givenName".equalsIgnoreCase(currentField)){ //givenName

    debug(logName, "CURRENT FIELD: " + currentField);

    if (firstName!=null){
      field.setReadOnly(true);    
      return firstName;
    }else{
      field.setReadOnly(false);
      return null;
    }

    debug(logName, "value: " + firstName);

  }

  if ("fullName".equalsIgnoreCase(currentField)){ //fullName

    debug(logName, "CURRENT FIELD: " + currentField);

    if (firstName != null && lastName!=null){
      fullName = firstName + " " + lastName;
      field.setReadOnly(true);
      return fullName;
    }else if (firstName != null){
      fullName = firstName;
      field.setReadOnly(true);
      return fullName;
    }else if (lastName != null){
      fullName = lastName;
      field.setReadOnly(true);
      return fullName;
    }else{
      field.setReadOnly(false);
    }

  }

  if ("isMailboxSetup".equalsIgnoreCase(currentField)){ //isMailboxSetup

    debug(logName, "CURRENT FIELD: " + currentField);

    if (Util.nullSafeCaseInsensitiveEq(identityType, "employee") || (Util.nullSafeCaseInsensitiveEq(identityType, "physician") && Util.nullSafeCaseInsensitiveEq(hrType, "EMP"))) {
      return "true";
    }else{
      return "false";
    }

  }

  if ("includeInGlobalAddressList".equalsIgnoreCase(currentField)){ //includeInGlobalAddressList

    debug(logName, "CURRENT FIELD: " + currentField);

    if (Util.nullSafeCaseInsensitiveEq(identityType, "employee") || (Util.nullSafeCaseInsensitiveEq(identityType, "physician") && Util.nullSafeCaseInsensitiveEq(hrType, "EMP"))) {
      return "true";
    } else{
      return "false";
    }

  }

  if ("orgUnitPath".equalsIgnoreCase(currentField)){ //orgUnitPath

    debug(logName, "CURRENT FIELD: " + currentField);

    String EA40 = "gsuiteStatus";
    String EA20 = "gsuiteMdm";
    String emplType = "employeeType";

    String EA40Value = "";
    String EA20Value = "";
    String emplTypeValue = "";
    List emplClassValues=new ArrayList();

    String customBusinessUnitKey ="businessUnitsForAutoProvisioning";
    String customMinsitryKey = "ministryForAutoProvisioning";
   
    boolean isAscTechConWSpecBU =	false;
    if (gsuiteCustomObject != null){
      Attributes attr = gsuiteCustomObject.getAttributes();
      if (attr != null){
        Map objectMap = attr.getMap();
        if (objectMap != null){
          gsuiteStatusMap = objectMap.get("gsuite_status_mapping");
          debug(logName, "gsuiteStatusMap: " + gsuiteStatusMap);

          emplClassValues = objectMap.get("emplClassForAutoProvisioning");
        }
      }
    }

    String GSuiteStatus=identity.getAttribute("gsuiteStatus");
    String businessUnit = identity.getAttribute("businessUnit");
    String ministry = identity.getAttribute("ministry");

   
    List businessUnitList = GeneralUtils.loadCustomList(customBusinessUnitKey, GSUITE_CUSTOM_OBJECT_NAME);

    if (empClass!=null && emplClassValues.contains(empClass)){
      GSuiteStatus="CWR_active_mail";
    }
    else if(Util.nullSafeCaseInsensitiveEq(identityType, "Contractor") @and businessUnit != null @and businessUnitList.contains(businessUnit)){
      GSuiteStatus="CWR_active_mail";
    }
    else{
      GSuiteStatus=identity.getAttribute("gsuiteStatus");
    }
    if (GSuiteStatus==null){
      if (Util.nullSafeCaseInsensitiveEq(identityType, "employee") || (Util.nullSafeCaseInsensitiveEq(identityType, "physician") && Util.nullSafeCaseInsensitiveEq(hrType, "EMP"))) {
        GSuiteStatus="EMP_active";
      }  else if (!(empClass!=null && emplClassValues.contains(empClass))){
        GSuiteStatus="CWR_active_nomail";
      }
      else if ((empClass!=null && emplClassValues.contains(empClass))){
        GSuiteStatus="CWR_active_mail";
      }
      else if(Util.nullSafeCaseInsensitiveEq(identityType, "Contractor") @and businessUnit != null @and businessUnitList.contains(businessUnit)){
        GSuiteStatus="CWR_active_mail";
      }
      else {
        GSuiteStatus="CWR_active_nomail";
      }//added closing bracket 8/25 AN
    }
    String GSuiteOU=GSuiteStatus+"#";
    if (identity.getAttribute("gsuiteMdm") != null){
      GSuiteOU=GSuiteStatus+"#"+identity.getAttribute("gsuiteMdm");
    }
    if (identity.getAttribute(EA20) != null){
      EA20Value = identity.getAttribute(EA20);
    }
    if (identity.getAttribute(emplType) != null){
      emplTypeValue = identity.getAttribute(emplType);
    }

    String tmpEa40Val = identity.getAttribute(EA40);

    if (tmpEa40Val==null){ 
      if (Util.nullSafeCaseInsensitiveEq(identityType, "employee") || (Util.nullSafeCaseInsensitiveEq(identityType, "physician") && Util.nullSafeCaseInsensitiveEq(hrType, "EMP"))) {
        tmpEa40Val="EMP_active";
      } else if (Util.nullSafeCaseInsensitiveEq(identityType, "contractor") && (empClass!=null && emplClassValues.contains(empClass))){
        tmpEa40Val="CWR_active_mail";
      }
      else if(Util.nullSafeCaseInsensitiveEq(identityType, "Contractor") @and businessUnit != null @and businessUnitList.contains(businessUnit)){
        tmpEa40Val="CWR_active_mail";
      }
      else {
        tmpEa40Val="CWR_active_nomail";
      }
    }
    System.out.println("!! tmpEa40Val: "+tmpEa40Val);
    System.out.println("!! EA20Value: "+EA20Value);
    System.out.println("!! emplTypeValue: "+emplTypeValue);

    if (void!=tmpEa40Val && Util.isNotNullOrEmpty(tmpEa40Val)){
      GSuiteOU = tmpEa40Val.toString()+"#"+EA20Value+"#"+emplTypeValue;         
    }

    System.out.println("!! GSuiteStatus: "+GSuiteStatus);
    System.out.println("!! gsuiteStatusMap: "+gsuiteStatusMap);
    System.out.println("!! GSuiteOU: "+GSuiteOU);

    log.error("!! GSuiteStatus: "+GSuiteStatus);
    log.error("!! gsuiteStatusMap: "+gsuiteStatusMap);
    log.error("!! GSuiteOU: "+GSuiteOU);
    if (GSuiteStatus!=null && gsuiteStatusMap != null && gsuiteStatusMap.containsKey(GSuiteOU)){
      String gsuiteString = (String) gsuiteStatusMap.get(GSuiteOU);
      if (gsuiteString != null && !gsuiteString.isEmpty() && gsuiteString.contains("#")){
        String[] splitString = gsuiteString.split("#");
        if (splitString != null && splitString.length > 0){
          return splitString[0]; 
        }
      }  
    } else{
      return null; 
    }

  }

  //End Common Field Logic

  debug(logName, "END COMMON FIELD LOGIC");

  debug(logName, "BEGIN TYPE-CONDTIONAL FIELD LOGIC");

  //Begin Type-Conditional Field Logic

  if (Util.nullSafeCaseInsensitiveEq(identityType, "contractor") || Util.nullSafeCaseInsensitiveEq(identityType, "non-hr contractor") || (Util.nullSafeCaseInsensitiveEq(identityType, "physician") && !Util.nullSafeCaseInsensitiveEq(hrType, "EMP"))) {

    debug(logName, "TYPE-CONDITION-MATCHED: " + "CWR, NonHR-CWR, or Non-EMP Physician");

    if (currentField.equalsIgnoreCase("familyName")){ //familyName

      debug(logName, "CURRENT FIELD: " + currentField);

      if (Util.isNotNullOrEmpty(gsuiteLN)){

        field.setReadOnly(true);
        return gsuiteLN;

      }else if (Util.isNullOrEmpty(gsuiteLN)){

        field.setReadOnly(true);
        if (Util.isNotNullOrEmpty(lastName) && Util.isNotNullOrEmpty(vendorName)) {
          gsuiteLN = lastName + " (" + vendorName + ")";
        } else if (Util.isNotNullOrEmpty(lastName)) {
          gsuiteLN = lastName;
        }

      }
      if (Util.isNotNullOrEmpty(gsuiteLN)){

        field.setReadOnly(true);
        return gsuiteLN;

      } else {

        field.setReadOnly(false);
        return null;
      }

    }

  }

  if (Util.nullSafeCaseInsensitiveEq(identityType, "employee") || (Util.nullSafeCaseInsensitiveEq(identityType, "physician") && Util.nullSafeCaseInsensitiveEq(hrType, "EMP"))) {

    debug(logName, "TYPE-CONDITION-MATCHED: " + "EMP, or Physician (employed)");

    if (currentField.equalsIgnoreCase("familyName")){ //familyName

      debug(logName, "CURRENT FIELD: " + currentField);

      if (Util.isNotNullOrEmpty(lastName)){

        field.setReadOnly(true);
        return lastName;

      }else{

        field.setReadOnly(false);
        return null;

      }
    }

  }

  if (Util.isNullOrEmpty(identityType)) {

    debug(logName, "TYPE-CONDITION-MATCHED: " + "identity has no type defined (i.e. null type)");

    if (currentField.equalsIgnoreCase("familyName")){ //familyName

      debug(logName, "CURRENT FIELD: " + currentField);

      if (Util.isNotNullOrEmpty(lastName)){

        field.setReadOnly(true);
        return lastName;

      }else{

        field.setReadOnly(false);
        return null;

      }

    }

  } 

  //End Type-Conditional Field Logic
